// namedFoldingRegionProvider.ts

export const NAMED_REGION_ID = 'namedRegion';
const REGION_PATTERN = /^\s*#region\b\s*(.*)/i;
const ENDREGION_PATTERN = /^\s*#endregion\b/i;

export interface NamedRegion {
  name: string;
  startLine: number;  // 1-based
  endLine: number;    // 1-based
}

export function computeNamedRegions(
  model: ITextModel,
  foldingRangesLimit: FoldingLimitReporter
): FoldingRegions {
  const lineCount = model.getLineCount();
  const stack: { line: number; name: string }[] = [];
  const regions: NamedRegion[] = [];

  for (let lineNum = 1; lineNum <= lineCount; lineNum++) {
    const line = model.getLineContent(lineNum);
    const startMatch = REGION_PATTERN.exec(line);
    if (startMatch) {
      stack.push({ line: lineNum, name: startMatch[1].trim() || `region ${lineNum}` });
      continue;
    }
    if (ENDREGION_PATTERN.test(line)) {
      if (stack.length > 0) {
        const { line: startLine, name } = stack.pop()!;
        regions.push({ name, startLine, endLine: lineNum });
      }
    }
  }

  // Sort by startLine ascending (required by FoldingRegions)
  regions.sort((a, b) => a.startLine - b.startLine);

  // Apply limit
  const limit = foldingRangesLimit.limit;
  const limited = regions.length > limit ? limit : false;
  foldingRangesLimit.update(regions.length, limited);

  const count = limited !== false ? limited : regions.length;
  const startIndexes = new Uint32Array(count);
  const endIndexes = new Uint32Array(count);
  const types: string[] = [];

  for (let i = 0; i < count; i++) {
    startIndexes[i] = regions[i].startLine;
    endIndexes[i] = regions[i].endLine;
    types[i] = regions[i].name;
  }

  return new FoldingRegions(startIndexes, endIndexes, types);
}

export function getNamedRegions(model: ITextModel): NamedRegion[] {
  const lineCount = model.getLineCount();
  const stack: { line: number; name: string }[] = [];
  const regions: NamedRegion[] = [];

  for (let lineNum = 1; lineNum <= lineCount; lineNum++) {
    const line = model.getLineContent(lineNum);
    const startMatch = REGION_PATTERN.exec(line);
    if (startMatch) {
      stack.push({ line: lineNum, name: startMatch[1].trim() || `region ${lineNum}` });
      continue;
    }
    if (ENDREGION_PATTERN.test(line)) {
      if (stack.length > 0) {
        const { line: startLine, name } = stack.pop()!;
        regions.push({ name, startLine, endLine: lineNum });
      }
    }
  }

  return regions.sort((a, b) => a.startLine - b.startLine);
}

export class NamedFoldingRegionProvider implements RangeProvider {
  readonly id = NAMED_REGION_ID;

  constructor(
    private readonly editorModel: ITextModel,
    private readonly foldingRangesLimit: FoldingLimitReporter
  ) {}

  dispose() {}

  compute(cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
    if (cancellationToken.isCancellationRequested) {
      return Promise.resolve(null);
    }
    return Promise.resolve(computeNamedRegions(this.editorModel, this.foldingRangesLimit));
  }
}
