export const NAMED_REGION_ID = 'namedRegion';

/** Matches `#region` lines, capturing an optional name: `#region My Name` */
const REGION_PATTERN = /^\s*#region\b\s*(.*)/i;
/** Matches `#endregion` lines */
const ENDREGION_PATTERN = /^\s*#endregion\b/i;

export interface NamedRegion {
	readonly name: string;
	readonly startLine: number; // 1-based
	readonly endLine: number;   // 1-based
}

/**
 * Scans `model` for `#region`/`#endregion` pairs and returns them sorted
 * by start line.  Unmatched `#region` markers (no closing `#endregion`) are
 * silently ignored.
 */
export function getNamedRegions(model: ITextModel): NamedRegion[] {
	const lineCount = model.getLineCount();
	const stack: { line: number; name: string }[] = [];
	const regions: NamedRegion[] = [];

	for (let lineNum = 1; lineNum <= lineCount; lineNum++) {
		const text = model.getLineContent(lineNum);
		const startMatch = REGION_PATTERN.exec(text);
		if (startMatch) {
			const name = startMatch[1].trim();
			stack.push({ line: lineNum, name: name || `region ${lineNum}` });
			continue;
		}
		if (ENDREGION_PATTERN.test(text) && stack.length > 0) {
			const { line: startLine, name } = stack.pop()!;
			regions.push({ name, startLine, endLine: lineNum });
		}
	}

	return regions.sort((a, b) => a.startLine - b.startLine);
}

/**
 * Computes folding regions for `#region`/`#endregion` pairs, storing each
 * region's name in the `types` array of the returned {@link FoldingRegions}.
 */
export function computeNamedRegions(model: ITextModel, foldingRangesLimit: FoldingLimitReporter): FoldingRegions {
	const regions = getNamedRegions(model).filter(r =>
		r.startLine <= MAX_LINE_NUMBER && r.endLine <= MAX_LINE_NUMBER
	);

	const limited = regions.length > foldingRangesLimit.limit ? foldingRangesLimit.limit : false;
	foldingRangesLimit.update(regions.length, limited);

	const count = limited !== false ? limited : regions.length;
	const startIndexes = new Uint32Array(count);
	const endIndexes = new Uint32Array(count);
	const types: string[] = [];

	for (let i = 0; i < count; i++) {
		startIndexes[i] = regions[i].startLine;
		endIndexes[i] = regions[i].endLine;
		types[i] = regions[i].name;
	}

	return new FoldingRegions(startIndexes, endIndexes, types);
}

// ---------------------------------------------------------------------------
// Decoration for named-region start lines
// ---------------------------------------------------------------------------

/** Applied to the full first column of every `#region <name>` line. */
const NAMED_REGION_START_DECORATION = ModelDecorationOptions.register({
	description: 'named-folding-region-start',
	stickiness: TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
	linesDecorationsClassName: 'named-region-start',
	linesDecorationsTooltip: nls.localize('namedRegion.tooltip', "Named folding region"),
});

/**
 * Replaces `existingDecorationIds` with new decorations that mark each
 * `#region` start line in `regions`.  Returns the new decoration IDs.
 */
export function applyNamedRegionDecorations(
	editor: ICodeEditor,
	regions: NamedRegion[],
	existingDecorationIds: string[]
): string[] {
	const newDecorations: IModelDeltaDecoration[] = regions.map(r => ({
		range: { startLineNumber: r.startLine, startColumn: 1, endLineNumber: r.startLine, endColumn: 1 },
		options: NAMED_REGION_START_DECORATION,
	}));
	return editor.deltaDecorations(existingDecorationIds, newDecorations);
}

// ---------------------------------------------------------------------------
// RangeProvider implementation
// ---------------------------------------------------------------------------

export class NamedFoldingRegionProvider implements RangeProvider {
	readonly id = NAMED_REGION_ID;

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter,
	) { }

	dispose() { }

	compute(cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
		if (cancellationToken.isCancellationRequested) {
			return Promise.resolve(null);
		}
		return Promise.resolve(computeNamedRegions(this.editorModel, this.foldingRangesLimit));
	}
}

// ---------------------------------------------------------------------------
// editor.action.goToNamedRegion  —  quick-pick navigation
// ---------------------------------------------------------------------------

interface NamedRegionPickItem extends IQuickPickItem {
	readonly region: NamedRegion;
}

export class GoToNamedRegionAction extends EditorAction {

	constructor() {
		super({
			id: 'editor.action.goToNamedRegion',
			label: nls.localize2('goToNamedRegion.label', "Go to Named Region"),
			precondition: undefined,
		});
	}

	override async run(accessor: ServicesAccessor, editor: ICodeEditor): Promise<void> {
		if (!editor.hasModel()) {
			return;
		}

		const quickInputService = accessor.get(IQuickInputService);
		const model = editor.getModel();
		const regions = getNamedRegions(model);

		if (regions.length === 0) {
			return;
		}

		// Apply decorations so the user sees the markers while picking.
		let decorationIds: string[] = applyNamedRegionDecorations(editor, regions, []);

		const items: NamedRegionPickItem[] = regions.map(r => ({
			label: r.name,
			description: nls.localize(
				'namedRegion.lineRange',
				"Lines {0} – {1}",
				r.startLine,
				r.endLine,
			),
			region: r,
		}));

		let accepted = false;
		const picked = await quickInputService.pick(items, {
			canPickMany: false,
			placeHolder: nls.localize('goToNamedRegion.placeholder', "Select a named region"),
			onDidFocus: item => {
				// Preview navigation while the user hovers over items.
				if (item) {
					const lineNumber = (item as NamedRegionPickItem).region.startLine;
					editor.revealLineInCenterIfOutsideViewport(lineNumber, ScrollType.Smooth);
				}
			},
		});

		if (picked) {
			accepted = true;
			const lineNumber = picked.region.startLine;
			editor.setPosition({ lineNumber, column: 1 });
			editor.revealLineInCenter(lineNumber, ScrollType.Smooth);
		}

		// Clear decorations once done; if cancelled, restore original view.
		decorationIds = editor.deltaDecorations(decorationIds, []);

		if (!accepted) {
			// Nothing to restore — the preview already moved the viewport;
			// the editor's undo/scroll history handles returning if desired.
			void decorationIds; // suppress unused-variable warning
		}
	}
}

registerEditorAction(GoToNamedRegionAction);

