/*---------------------------------------------------------------------------------------------
 *  Copyright (c) Microsoft Corporation. All rights reserved.
 *  Licensed under the MIT License. See License.txt in the project root for license information.
 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';
import { FoldingLimitReporter } from '../../browser/folding.js';
import { computeNamedRegions, getNamedRegions, NamedRegion } from '../../browser/namedFoldingRegionProvider.js';

// A simple limit reporter that records whether the limit was applied.
function makeLimitReporter(limit = 65535): FoldingLimitReporter & { limited: number | false } {
	return {
		limit,
		limited: false as number | false,
		update(_computed: number, limited: number | false) { this.limited = limited; },
	};
}

suite('Named Folding Regions', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	// -----------------------------------------------------------------------
	// getNamedRegions
	// -----------------------------------------------------------------------

	suite('getNamedRegions', () => {

		test('returns empty array when no regions are present', () => {
			const model = createTextModel([
				'const x = 1;',
				'function foo() {}',
			].join('\n'));
			assert.deepStrictEqual(getNamedRegions(model), []);
			model.dispose();
		});

		test('detects a single named region', () => {
			const model = createTextModel([
				/* 1 */ '#region Utilities',
				/* 2 */ 'function helper() {}',
				/* 3 */ '#endregion',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 1);
			assert.strictEqual(regions[0].name, 'Utilities');
			assert.strictEqual(regions[0].startLine, 1);
			assert.strictEqual(regions[0].endLine, 3);
			model.dispose();
		});

		test('uses a default name when no name follows #region', () => {
			const model = createTextModel([
				/* 1 */ '#region',
				/* 2 */ 'let y = 2;',
				/* 3 */ '#endregion',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 1);
			assert.strictEqual(regions[0].name, 'region 1');
			model.dispose();
		});

		test('detects multiple sibling regions sorted by start line', () => {
			const model = createTextModel([
				/* 1 */ '#region Alpha',
				/* 2 */ 'A',
				/* 3 */ '#endregion',
				/* 4 */ '#region Beta',
				/* 5 */ 'B',
				/* 6 */ '#endregion',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 2);
			assert.strictEqual(regions[0].name, 'Alpha');
			assert.strictEqual(regions[0].startLine, 1);
			assert.strictEqual(regions[0].endLine, 3);
			assert.strictEqual(regions[1].name, 'Beta');
			assert.strictEqual(regions[1].startLine, 4);
			assert.strictEqual(regions[1].endLine, 6);
			model.dispose();
		});

		test('handles nested regions (inner closes before outer)', () => {
			const model = createTextModel([
				/* 1 */ '#region Outer',
				/* 2 */ '  #region Inner',
				/* 3 */ '  // code',
				/* 4 */ '  #endregion',
				/* 5 */ '#endregion',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 2);
			// Sorted by start line: Inner (2) comes after Outer (1).
			const inner = regions.find(r => r.name === 'Inner')!;
			const outer = regions.find(r => r.name === 'Outer')!;
			assert.ok(inner, 'Inner region not found');
			assert.ok(outer, 'Outer region not found');
			assert.strictEqual(inner.startLine, 2);
			assert.strictEqual(inner.endLine, 4);
			assert.strictEqual(outer.startLine, 1);
			assert.strictEqual(outer.endLine, 5);
		});

		test('ignores unmatched #region (no closing #endregion)', () => {
			const model = createTextModel([
				/* 1 */ '#region Orphan',
				/* 2 */ 'orphan code',
				/* 3 */ '// end of file',
			].join('\n'));
			assert.deepStrictEqual(getNamedRegions(model), []);
			model.dispose();
		});

		test('is case-insensitive for markers', () => {
			const model = createTextModel([
				/* 1 */ '#REGION CaseTest',
				/* 2 */ 'code',
				/* 3 */ '#ENDREGION',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 1);
			assert.strictEqual(regions[0].name, 'CaseTest');
			model.dispose();
		});

		test('tolerates leading whitespace before markers', () => {
			const model = createTextModel([
				/* 1 */ '   #region Indented',
				/* 2 */ '   code',
				/* 3 */ '   #endregion',
			].join('\n'));
			const regions = getNamedRegions(model);
			assert.strictEqual(regions.length, 1);
			assert.strictEqual(regions[0].name, 'Indented');
			model.dispose();
		});

		test('trims trailing whitespace from region name', () => {
			const model = createTextModel('#region  Trimmed  \n code \n#endregion');
			const regions = getNamedRegions(model);
			assert.strictEqual(regions[0].name, 'Trimmed');
			model.dispose();
		});
	});

	// -----------------------------------------------------------------------
	// computeNamedRegions  (FoldingRegions output)
	// -----------------------------------------------------------------------

	suite('computeNamedRegions', () => {

		function r(region: NamedRegion): { start: number; end: number; name: string } {
			return { start: region.startLine, end: region.endLine, name: region.name };
		}

		test('returns empty FoldingRegions when no regions are present', () => {
			const model = createTextModel('line1\nline2\n');
			const reporter = makeLimitReporter();
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.length, 0);
			assert.strictEqual(reporter.limited, false);
			model.dispose();
		});

		test('start/end line numbers match the model lines', () => {
			const model = createTextModel([
				/* 1 */ '#region Section',
				/* 2 */ 'body',
				/* 3 */ '#endregion',
			].join('\n'));
			const reporter = makeLimitReporter();
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.length, 1);
			assert.strictEqual(result.getStartLineNumber(0), 1);
			assert.strictEqual(result.getEndLineNumber(0), 3);
			assert.strictEqual(result.getType(0), 'Section');
			model.dispose();
		});

		test('stores region names in the types array', () => {
			const model = createTextModel([
				/* 1 */ '#region A',
				/* 2 */ 'a',
				/* 3 */ '#endregion',
				/* 4 */ '#region B',
				/* 5 */ 'b',
				/* 6 */ '#endregion',
			].join('\n'));
			const reporter = makeLimitReporter();
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.length, 2);
			assert.strictEqual(result.getType(0), 'A');
			assert.strictEqual(result.getType(1), 'B');
			model.dispose();
		});

		test('respects the foldingRangesLimit', () => {
			const lines: string[] = [];
			for (let i = 1; i <= 10; i++) {
				lines.push(`#region R${i}`, `line`, `#endregion`);
			}
			const model = createTextModel(lines.join('\n'));
			const reporter = makeLimitReporter(5);
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.length, 5);
			assert.strictEqual(reporter.limited, 5);
			model.dispose();
		});

		test('does not apply a limit when count is within limit', () => {
			const model = createTextModel([
				/* 1 */ '#region X',
				/* 2 */ 'x',
				/* 3 */ '#endregion',
			].join('\n'));
			const reporter = makeLimitReporter(100);
			computeNamedRegions(model, reporter);
			assert.strictEqual(reporter.limited, false);
			model.dispose();
		});

		test('regions are sorted by start line (ascending)', () => {
			// Build with nested regions; after sorting by start line the order
			// must be ascending.
			const model = createTextModel([
				/* 1 */ '#region First',
				/* 2 */ '  #region Second',
				/* 3 */ '  code',
				/* 4 */ '  #endregion',
				/* 5 */ '#endregion',
			].join('\n'));
			const reporter = makeLimitReporter();
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.length, 2);
			assert.ok(
				result.getStartLineNumber(0) <= result.getStartLineNumber(1),
				'Regions must be sorted ascending by start line'
			);
			model.dispose();
		});

		test('hasTypes() returns true when names are present', () => {
			const model = createTextModel('#region Named\ncode\n#endregion');
			const reporter = makeLimitReporter();
			const result = computeNamedRegions(model, reporter);
			assert.strictEqual(result.hasTypes(), true);
			model.dispose();
		});

		test('helper function r() maps NamedRegion to expected shape', () => {
			const nr: NamedRegion = { name: 'Z', startLine: 7, endLine: 9 };
			assert.deepStrictEqual(r(nr), { start: 7, end: 9, name: 'Z' });
		});
	});
});

