    63			r.startLine <= MAX_LINE_NUMBER && r.endLine <= MAX_LINE_NUMBER
    64		);
    65	
    66		const limited = regions.length > foldingRangesLimit.limit ? foldingRangesLimit.limit : false;
    67		foldingRangesLimit.update(regions.length, limited);
    68	
    69		const count = limited !== false ? limited : regions.length;
    70		const startIndexes = new Uint32Array(count);
    71		const endIndexes = new Uint32Array(count);
    72		const types: string[] = [];
    73	
    74		for (let i = 0; i < count; i++) {
    75			startIndexes[i] = regions[i].startLine;
    76			endIndexes[i] = regions[i].endLine;
    77			types[i] = regions[i].name;
    78		}
    79	
    80		return new FoldingRegions(startIndexes, endIndexes, types);
    81	}
    82	
    83	// ---------------------------------------------------------------------------
    84	// Decoration for named-region start lines
    85	// ---------------------------------------------------------------------------
    86	
    87	/** Applied to the full first column of every `#region <name>` line. */
    88	const NAMED_REGION_START_DECORATION = ModelDecorationOptions.register({
    89		description: 'named-folding-region-start',
    90		stickiness: TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
    91		linesDecorationsClassName: 'named-region-start',
    92		linesDecorationsTooltip: nls.localize('namedRegion.tooltip', "Named folding region"),
    93	});
    94	
    95	/**
    96	 * Replaces `existingDecorationIds` with new decorations that mark each
    97	 * `#region` start line in `regions`.  Returns the new decoration IDs.
    98	 */
    99	export function applyNamedRegionDecorations(
   100		editor: ICodeEditor,
   101		regions: NamedRegion[],
   102		existingDecorationIds: string[]
   103	): string[] {
   104		const newDecorations: IModelDeltaDecoration[] = regions.map(r => ({
   105			range: { startLineNumber: r.startLine, startColumn: 1, endLineNumber: r.startLine, endColumn: 1 },
   106			options: NAMED_REGION_START_DECORATION,
   107		}));
   108		return editor.deltaDecorations(existingDecorationIds, newDecorations);
   109	}
