    19	/** Matches `#region` lines, capturing an optional name: `#region My Name` */
    20	const REGION_PATTERN = /^\s*#region\b\s*(.*)/i;
    21	/** Matches `#endregion` lines */
    22	const ENDREGION_PATTERN = /^\s*#endregion\b/i;
    23	
    24	export interface NamedRegion {
    25		readonly name: string;
    26		readonly startLine: number; // 1-based
    27		readonly endLine: number;   // 1-based
    28	}
    29	
    30	/**
    31	 * Scans `model` for `#region`/`#endregion` pairs and returns them sorted
    32	 * by start line.  Unmatched `#region` markers (no closing `#endregion`) are
    33	 * silently ignored.
    34	 */
    35	export function getNamedRegions(model: ITextModel): NamedRegion[] {
    36		const lineCount = model.getLineCount();
    37		const stack: { line: number; name: string }[] = [];
    38		const regions: NamedRegion[] = [];
    39	
    40		for (let lineNum = 1; lineNum <= lineCount; lineNum++) {
    41			const text = model.getLineContent(lineNum);
    42			const startMatch = REGION_PATTERN.exec(text);
    43			if (startMatch) {
    44				const name = startMatch[1].trim();
    45				stack.push({ line: lineNum, name: name || `region ${lineNum}` });
    46				continue;
    47			}
    48			if (ENDREGION_PATTERN.test(text) && stack.length > 0) {
    49				const { line: startLine, name } = stack.pop()!;
    50				regions.push({ name, startLine, endLine: lineNum });
    51			}
    52		}
    53	
    54		return regions.sort((a, b) => a.startLine - b.startLine);
    55	}
